@page "/tickets"
@using sv_fd41847613f843368cfe763fe13ac1c6.Services
@inject ITicketService TicketService
@rendermode InteractiveServer

<PageTitle>Help Desk Tickets</PageTitle>

<div class="tickets-dashboard">
    <!-- Top Bar -->
    <div class="top-bar">
        <div class="search-box">
            <input type="text" placeholder="Search tickets by subject..."
                   @bind="searchQuery" @bind:event="oninput"
                   @onkeyup="OnSearchKeyUp" />
        </div>
        <div class="status-tabs">
            @foreach (var tab in statusTabs)
            {
                <button class="tab-btn @(statusFilter == tab.Value ? "active" : "")"
                        @onclick="() => SetStatusFilter(tab.Value)">
                    @tab.Label
                </button>
            }
        </div>
        <div class="priority-filter">
            <select @onchange="OnPriorityChanged">
                @foreach (var p in priorityOptions)
                {
                    <option value="@p.Value" selected="@(priorityFilter == p.Value)">@p.Label</option>
                }
            </select>
        </div>
    </div>

    <!-- Main Panels -->
    <div class="panels">
        <!-- Left Panel -->
        <div class="left-panel">
            @if (tickets == null)
            {
                <p class="loading">Loading tickets...</p>
            }
            else if (tickets.Count == 0)
            {
                <p class="no-tickets">No tickets found.</p>
            }
            else
            {
                @foreach (var ticket in tickets)
                {
                    <div class="ticket-card @(selectedTicket?.Id == ticket.Id ? "active" : "")"
                         @onclick="() => SelectTicket(ticket)">
                        <div class="ticket-card-header">
                            <span class="priority-dot @GetPriorityClass(ticket.Priority)"></span>
                            <span class="ticket-subject">@ticket.Subject</span>
                        </div>
                        <div class="ticket-card-meta">
                            <span class="ticket-requester">@ticket.Requester</span>
                            <span class="ticket-time">@FormatRelativeTime(ticket.CreatedAt)</span>
                        </div>
                        <div class="ticket-card-footer">
                            <span class="status-badge @GetStatusClass(ticket.Status)">@ticket.Status</span>
                        </div>
                    </div>
                }
            }
        </div>

        <!-- Right Panel -->
        <div class="right-panel">
            @if (selectedTicket == null)
            {
                <div class="no-selection">
                    <p>Select a ticket to view details</p>
                </div>
            }
            else
            {
                <div class="detail-view">
                    <div class="detail-header">
                        <h2>@selectedTicket.Subject</h2>
                        <div class="detail-controls">
                            <select @onchange="OnStatusChanged">
                                @foreach (var s in allStatuses)
                                {
                                    <option value="@s" selected="@(selectedTicket.Status == s)">@s</option>
                                }
                            </select>
                            <span class="priority-badge @GetPriorityClass(selectedTicket.Priority)">@selectedTicket.Priority</span>
                        </div>
                        <p class="detail-meta">Opened by <strong>@selectedTicket.Requester</strong> on @selectedTicket.CreatedAt.ToString("MMMM d, yyyy")</p>
                    </div>

                    <div class="detail-body">
                        <p>@selectedTicket.Description</p>
                    </div>

                    <div class="comments-section">
                        <h3>Comments</h3>
                        @if (comments == null)
                        {
                            <p class="loading">Loading comments...</p>
                        }
                        else if (comments.Count == 0)
                        {
                            <p class="no-comments">No comments yet.</p>
                        }
                        else
                        {
                            @foreach (var comment in comments)
                            {
                                <div class="comment">
                                    <div class="comment-header">
                                        <strong>@comment.Author</strong>
                                        <span class="comment-time">@comment.PostedAt.ToString("MMM d, yyyy h:mm tt")</span>
                                    </div>
                                    <p class="comment-text">@comment.Text</p>
                                </div>
                            }
                        }

                        <div class="add-comment">
                            <textarea placeholder="Add a comment..." @bind="newCommentText"></textarea>
                            <button @onclick="SubmitComment" disabled="@string.IsNullOrWhiteSpace(newCommentText)">Submit</button>
                        </div>
                    </div>
                </div>
            }
        </div>
    </div>

    <!-- Footer Bar -->
    <div class="footer-bar">
        @if (tickets != null)
        {
            var openCount = tickets.Count(t => t.Status == "Open");
            var inProgressCount = tickets.Count(t => t.Status == "In Progress");
            var resolvedCount = tickets.Count(t => t.Status == "Resolved");
            <span>@openCount open · @inProgressCount in progress · @resolvedCount resolved</span>
        }
    </div>
</div>

@code {
    private List<Ticket>? tickets;
    private List<Comment>? comments;
    private Ticket? selectedTicket;
    private string? searchQuery;
    private string? statusFilter;
    private string? priorityFilter;
    private string newCommentText = string.Empty;

    private readonly (string Label, string? Value)[] statusTabs =
    [
        ("All", null),
        ("Open", "Open"),
        ("In Progress", "In Progress"),
        ("Resolved", "Resolved")
    ];

    private readonly (string Label, string? Value)[] priorityOptions =
    [
        ("All Priorities", null),
        ("Critical", "Critical"),
        ("High", "High"),
        ("Medium", "Medium"),
        ("Low", "Low")
    ];

    private readonly string[] allStatuses = ["Open", "In Progress", "Resolved"];

    protected override async Task OnInitializedAsync()
    {
        await LoadTickets();
    }

    private async Task LoadTickets()
    {
        tickets = await TicketService.GetTicketsAsync(statusFilter, priorityFilter, searchQuery);
    }

    private async Task SetStatusFilter(string? filter)
    {
        statusFilter = filter;
        await LoadTickets();
    }

    private async Task OnPriorityChanged(ChangeEventArgs e)
    {
        var value = e.Value?.ToString();
        priorityFilter = string.IsNullOrEmpty(value) ? null : value;
        await LoadTickets();
    }

    private async Task OnSearchKeyUp(KeyboardEventArgs e)
    {
        await LoadTickets();
    }

    private async Task SelectTicket(Ticket ticket)
    {
        selectedTicket = ticket;
        comments = await TicketService.GetCommentsAsync(ticket.Id);
    }

    private async Task OnStatusChanged(ChangeEventArgs e)
    {
        if (selectedTicket == null) return;
        var newStatus = e.Value?.ToString();
        if (string.IsNullOrEmpty(newStatus) || newStatus == selectedTicket.Status) return;

        await TicketService.UpdateStatusAsync(selectedTicket.Id, newStatus);
        selectedTicket = selectedTicket with { Status = newStatus };
        await LoadTickets();
    }

    private async Task SubmitComment()
    {
        if (selectedTicket == null || string.IsNullOrWhiteSpace(newCommentText)) return;

        await TicketService.AddCommentAsync(selectedTicket.Id, newCommentText);
        newCommentText = string.Empty;
        comments = await TicketService.GetCommentsAsync(selectedTicket.Id);
    }

    private static string GetPriorityClass(string priority) => priority switch
    {
        "Critical" => "priority-critical",
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => ""
    };

    private static string GetStatusClass(string status) => status switch
    {
        "Open" => "status-open",
        "In Progress" => "status-in-progress",
        "Resolved" => "status-resolved",
        _ => ""
    };

    private static string FormatRelativeTime(DateTime createdAt)
    {
        var span = DateTime.UtcNow - createdAt;

        if (span.TotalMinutes < 1) return "just now";
        if (span.TotalMinutes < 60) return $"{(int)span.TotalMinutes} minutes ago";
        if (span.TotalHours < 24) return $"{(int)span.TotalHours} hours ago";
        if (span.TotalDays < 30) return $"{(int)span.TotalDays} days ago";
        if (span.TotalDays < 365) return $"{(int)(span.TotalDays / 30)} months ago";
        return $"{(int)(span.TotalDays / 365)} years ago";
    }
}

.tickets-dashboard {
    display: flex;
    flex-direction: column;
    height: 100vh;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* Top Bar */
.top-bar {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-bottom: 1px solid #dee2e6;
    flex-wrap: wrap;
}

.search-box input {
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    width: 250px;
    font-size: 0.875rem;
}

.status-tabs {
    display: flex;
    gap: 0.25rem;
}

.tab-btn {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ced4da;
    background: white;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.8125rem;
    transition: all 0.15s;
}

.tab-btn:hover {
    background: #e9ecef;
}

.tab-btn.active {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

.priority-filter select {
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.875rem;
    background: white;
}

/* Panels */
.panels {
    display: flex;
    flex: 1;
    overflow: hidden;
}

.left-panel {
    width: 40%;
    overflow-y: auto;
    border-right: 1px solid #dee2e6;
    background: #fff;
}

.right-panel {
    width: 60%;
    overflow-y: auto;
    background: #fff;
    padding: 1.5rem;
}

/* Ticket Cards */
.ticket-card {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #eee;
    cursor: pointer;
    transition: background 0.15s;
}

.ticket-card:hover {
    background: #f1f3f5;
}

.ticket-card.active {
    background: #e7f1ff;
    border-left: 3px solid #0d6efd;
}

.ticket-card-header {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.25rem;
}

.priority-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
}

.priority-critical {
    background-color: #dc3545;
}

.priority-high {
    background-color: #fd7e14;
}

.priority-medium {
    background-color: #ffc107;
}

.priority-low {
    background-color: #6c757d;
}

.ticket-subject {
    font-weight: 500;
    font-size: 0.875rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    flex: 1;
}

.ticket-card-meta {
    display: flex;
    justify-content: space-between;
    font-size: 0.75rem;
    color: #6c757d;
    margin-bottom: 0.25rem;
}

.ticket-card-footer {
    display: flex;
}

/* Status Badges */
.status-badge {
    font-size: 0.6875rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    font-weight: 500;
}

.status-open {
    background: #d1ecf1;
    color: #0c5460;
}

.status-in-progress {
    background: #fff3cd;
    color: #856404;
}

.status-resolved {
    background: #d4edda;
    color: #155724;
}

/* Right Panel - No Selection */
.no-selection {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #6c757d;
    font-size: 1rem;
}

/* Detail View */
.detail-header h2 {
    margin: 0 0 0.5rem 0;
    font-size: 1.25rem;
}

.detail-controls {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 0.5rem;
}

.detail-controls select {
    padding: 0.35rem 0.6rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.8125rem;
}

.priority-badge {
    padding: 0.2rem 0.6rem;
    border-radius: 10px;
    font-size: 0.75rem;
    font-weight: 600;
    color: white;
}

.detail-meta {
    font-size: 0.8125rem;
    color: #6c757d;
    margin: 0.5rem 0;
}

.detail-body {
    padding: 1rem 0;
    border-top: 1px solid #eee;
    border-bottom: 1px solid #eee;
    margin: 1rem 0;
    line-height: 1.6;
    font-size: 0.9rem;
}

/* Comments */
.comments-section h3 {
    font-size: 1rem;
    margin-bottom: 0.75rem;
}

.comment {
    padding: 0.75rem;
    background: #f8f9fa;
    border-radius: 6px;
    margin-bottom: 0.5rem;
}

.comment-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.25rem;
    font-size: 0.8125rem;
}

.comment-time {
    color: #6c757d;
    font-size: 0.75rem;
}

.comment-text {
    margin: 0;
    font-size: 0.875rem;
    line-height: 1.5;
}

.add-comment {
    margin-top: 1rem;
}

.add-comment textarea {
    width: 100%;
    min-height: 80px;
    padding: 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.875rem;
    resize: vertical;
    font-family: inherit;
}

.add-comment button {
    margin-top: 0.5rem;
    padding: 0.5rem 1rem;
    background: #0d6efd;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.875rem;
}

.add-comment button:hover {
    background: #0b5ed7;
}

.add-comment button:disabled {
    background: #6c757d;
    cursor: not-allowed;
}

/* Footer */
.footer-bar {
    padding: 0.5rem 1rem;
    background: #f8f9fa;
    border-top: 1px solid #dee2e6;
    font-size: 0.8125rem;
    color: #495057;
    text-align: center;
}

/* Utility */
.loading, .no-tickets, .no-comments {
    padding: 1rem;
    color: #6c757d;
    font-size: 0.875rem;
}

