    background: #f8f9fa;
    border-bottom: 1px solid #dee2e6;
    flex-wrap: wrap;
}

.search-box input {
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    width: 250px;
    font-size: 0.875rem;
}

.status-tabs {
    display: flex;
    gap: 0.25rem;
}

.tab-btn {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ced4da;
    background: white;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.8125rem;
    transition: all 0.15s;
}

.tab-btn:hover {
    background: #e9ecef;
}

.tab-btn.active {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

.priority-filter select {
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.875rem;
    background: white;
}

/* Panels */
.panels {
    display: flex;
    flex: 1;
    overflow: hidden;
}

.left-panel {
    width: 40%;
    overflow-y: auto;
    border-right: 1px solid #dee2e6;
    background: #fff;
}

.right-panel {
    width: 60%;
    overflow-y: auto;
    background: #fff;
    padding: 1.5rem;
}

/* Ticket Cards */
.ticket-card {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #eee;
    cursor: pointer;
    transition: background 0.15s;
}

.ticket-card:hover {
    background: #f1f3f5;
}

.ticket-card.active {
    background: #e7f1ff;
    border-left: 3px solid #0d6efd;
}

.ticket-card-header {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.25rem;
}

.priority-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
}

.priority-critical {
    background-color: #dc3545;
}

.priority-high {
    background-color: #fd7e14;
}

.priority-medium {
    background-color: #ffc107;
}

.priority-low {
    background-color: #6c757d;
}

.ticket-subject {
    font-weight: 500;
    font-size: 0.875rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    flex: 1;
}

.ticket-card-meta {
    display: flex;
    justify-content: space-between;
    font-size: 0.75rem;
    color: #6c757d;
    margin-bottom: 0.25rem;
}

.ticket-card-footer {
    display: flex;
}

/* Status Badges */
.status-badge {
    font-size: 0.6875rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    font-weight: 500;
}

.status-open {
    background: #d1ecf1;
    color: #0c5460;
}

.status-in-progress {
    background: #fff3cd;
    color: #856404;
}

.status-resolved {
    background: #d4edda;
    color: #155724;
}

/* Right Panel - No Selection */
.no-selection {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #6c757d;
    font-size: 1rem;
}

/* Detail View */
.detail-header h2 {
    margin: 0 0 0.5rem 0;
    font-size: 1.25rem;
}

.detail-controls {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 0.5rem;
}

.detail-controls select {
    padding: 0.35rem 0.6rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.8125rem;
}

.priority-badge {
    padding: 0.2rem 0.6rem;
    border-radius: 10px;
    font-size: 0.75rem;
    font-weight: 600;
    color: white;
}

.detail-meta {
    font-size: 0.8125rem;
    color: #6c757d;
    margin: 0.5rem 0;
}

.detail-body {
    padding: 1rem 0;
    border-top: 1px solid #eee;
    border-bottom: 1px solid #eee;
    margin: 1rem 0;
    line-height: 1.6;
    font-size: 0.9rem;
}

/* Comments */
.comments-section h3 {
    font-size: 1rem;
    margin-bottom: 0.75rem;
}

.comment {
    padding: 0.75rem;
    background: #f8f9fa;
    border-radius: 6px;
    margin-bottom: 0.5rem;
}

.comment-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.25rem;
    font-size: 0.8125rem;
}

.comment-time {
    color: #6c757d;
    font-size: 0.75rem;
}

.comment-text {
    margin: 0;
    font-size: 0.875rem;
    line-height: 1.5;
}

.add-comment {
    margin-top: 1rem;
}

.add-comment textarea {
    width: 100%;
    min-height: 80px;
    padding: 0.5rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.875rem;
    resize: vertical;
    font-family: inherit;
}

.add-comment button {
    margin-top: 0.5rem;
    padding: 0.5rem 1rem;
    background: #0d6efd;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.875rem;
}

.add-comment button:hover {
    background: #0b5ed7;
}

.add-comment button:disabled {
    background: #6c757d;
    cursor: not-allowed;
}

/* Footer */
.footer-bar {
    padding: 0.5rem 1rem;
    background: #f8f9fa;
    border-top: 1px solid #dee2e6;
    font-size: 0.8125rem;
    color: #495057;
    text-align: center;
}

/* Utility */
.loading, .no-tickets, .no-comments {
    padding: 1rem;
    color: #6c757d;
    font-size: 0.875rem;
}

