toolArgs.file_text:
@page "/tickets"
@using sv_fd41847613f843368cfe763fe13ac1c6.Services
@inject ITicketService TicketService
@rendermode InteractiveServer

<PageTitle>Help Desk Tickets</PageTitle>

<div class="tickets-dashboard">
    <!-- Top Bar -->
    <div class="top-bar">
        <div class="search-box">
            <input type="text" placeholder="Search tickets by subject..."
                   @bind="searchQuery" @bind:event="oninput"
                   @onkeyup="OnSearchKeyUp" />
        </div>
        <div class="status-tabs">
            @foreach (var tab in statusTabs)
            {
                <button class="tab-btn @(statusFilter == tab.Value ? "active" : "")"
                        @onclick="() => SetStatusFilter(tab.Value)">
                    @tab.Label
                </button>
            }
        </div>
        <div class="priority-filter">
            <select @onchange="OnPriorityChanged">
                @foreach (var p in priorityOptions)
                {
                    <option value="@p.Value" selected="@(priorityFilter == p.Value)">@p.Label</option>
                }
            </select>
        </div>
    </div>

    <!-- Main Panels -->
    <div class="panels">
        <!-- Left Panel -->
        <div class="left-panel">
            @if (tickets == null)
            {
                <p class="loading">Loading tickets...</p>
            }
            else if (tickets.Count == 0)
            {
                <p class="no-tickets">No tickets found.</p>
            }
            else
            {
                @foreach (var ticket in tickets)
                {
                    <div class="ticket-card @(selectedTicket?.Id == ticket.Id ? "active" : "")"
                         @onclick="() => SelectTicket(ticket)">
                        <div class="ticket-card-header">
                            <span class="priority-dot @GetPriorityClass(ticket.Priority)"></span>
                            <span class="ticket-subject">@ticket.Subject</span>
                        </div>
                        <div class="ticket-card-meta">
                            <span class="ticket-requester">@ticket.Requester</span>
                            <span class="ticket-time">@FormatRelativeTime(ticket.CreatedAt)</span>
                        </div>
                        <div class="ticket-card-footer">
                            <span class="status-badge @GetStatusClass(ticket.Status)">@ticket.Status</span>
                        </div>
                    </div>
                }
            }
        </div>

        <!-- Right Panel -->
        <div class="right-panel">
            @if (selectedTicket == null)
            {
                <div class="no-selection">
                    <p>Select a ticket to view details</p>
                </div>
            }
            else
            {
                <div class="detail-view">
                    <div class="detail-header">
                        <h2>@selectedTicket.Subject</h2>
                        <div class="detail-controls">
                            <select @onchange="OnStatusChanged">
                                @foreach (var s in allStatuses)
                                {
                                    <option value="@s" selected="@(selectedTicket.Status == s)">@s</option>
                                }
                            </select>
                            <span class="priority-badge @GetPriorityClass(selectedTicket.Priority)">@selectedTicket.Priority</span>
                        </div>
                        <p class="detail-meta">Opened by <strong>@selectedTicket.Requester</strong> on @selectedTicket.CreatedAt.ToString("MMMM d, yyyy")</p>
                    </div>

                    <div class="detail-body">
                        <p>@selectedTicket.Description</p>
                    </div>

                    <div class="comments-section">
                        <h3>Comments</h3>
                        @if (comments == null)
                        {
                            <p class="loading">Loading comments...</p>
                        }
                        else if (comments.Count == 0)
                        {
                            <p class="no-comments">No comments yet.</p>
                        }
                        else
                        {
                            @foreach (var comment in comments)
                            {
                                <div class="comment">
                                    <div class="comment-header">
                                        <strong>@comment.Author</strong>
                                        <span class="comment-time">@comment.PostedAt.ToString("MMM d, yyyy h:mm tt")</span>
                                    </div>
                                    <p class="comment-text">@comment.Text</p>
                                </div>
                            }
                        }

                        <div class="add-comment">
